    14→part 'login_state_controller.g.dart';
    15→
    16→@Riverpod(keepAlive: true)
    17→class LoginStateController extends _$LoginStateController {
    18→  static final _fc =
    19→      failureCodeBuilder.category('CLS'); // Controller-LoginState
    20→
    21→  bool _mounted = true;
    22→
    23→  AuthClient get _authClient => ref.read(authClientProvider);
    24→
    25→  ProfileStorage get _profileStorage => ref.read(profileStorageProvider);
    26→
    27→  // NOTE:
    28→  // [supabase.GoTrueClient] automatically restore session when [Supabase.initialize] is called.
    29→  // In addition to this, calling [goTrueClient.restoreSession] in the constructor of this class
    30→  // causes an exception.
    31→  @override
    32→  FutureOr<bool> build() {
    33→    _mounted = true;
    34→    ref.onDispose(() => _mounted = false);
    35→
    36→    ref.watch(authClientProvider);
    37→    return false;
    38→  }
    39→
    40→  /// Signs in using Supabase auth
    41→  Future<Result<Failure, bool>> signInWithPassword(
    42→      String email, String password, bool saveCredentials) async {
    43→    state = const AsyncValue.loading();
    44→    final res =
    45→        await _authClient.signInWithPassword(email, password, saveCredentials);
    46→
    47→    // UnconfirmedEmailFailure の場合の処理
    48→    // 複数アカウントのサインアップ時に発生する `pendingUserId` 不整合問題は、
    49→    // auth_client.dart の _getEmailVerificationStatus で userId を取得して
    50→    // setPendingSignUpUserId することで解決されている
    51→    //
    52→    // 発生シナリオと解決方法
    53→    // 1. email1/password1/birthday1 でサインアップ（setPendingUserId に email1 の userId）
    54→    // 2. メール未検証のまま戻る
    55→    // 3. email2/password2/birthday2 でサインアップ（setPendingUserId に email2 の userId）
    56→    // 4. email2 はメール検証してログイン ( setPendingUserId が null になる)
    57→    // 5. email2 でログアウト
    58→    // 6. email1 でログイン試行
    59→    // 7. UnconfirmedEmailFailure を検知（この時 _getEmailVerificationStatus で email1 の userId を取得し setPendingUserId）
    60→
    61→    // Refresh user's accessible contents after successful login
    62→    if (res.hasRight && _mounted) {
    63→      await ref
    64→          .read(userAccessibleContentsControllerProvider.notifier)
    65→          .refresh();
    66→    }
    67→
    68→    if (!_mounted) return res;
    69→    state = res.fold((l) => AsyncValue.error(l, StackTrace.current),
    70→        (r) => const AsyncValue.data(true));
    71→    return res;
    72→  }
    73→
    74→  /// Sign out using Supabase auth
    75→  Future<Result<Failure, bool>> signOut() async {
    76→    state = const AsyncValue.loading();
    77→    final res = await _authClient.signOut();
    78→
    79→    // Clear user's accessible contents after sign out
    80→    if (_mounted) {
    81→      ref.invalidate(userAccessibleContentsControllerProvider);
    82→    }
    83→
    84→    if (!_mounted) return res;
    85→    state = res.fold((l) => AsyncValue.error(l, StackTrace.current),
    86→        (r) => const AsyncValue.data(true));
    87→    return res;
    88→  }
    89→
    90→  /// Switch team if user belongs to multiple teams
    91→  /// NOTE: implement here for renew LoginStateController state
    92→  Future<Result<Failure, bool>> switchTeam(
    93→    String teamId,
    94→  ) async {
    95→    final fc = _fc.category('SWTM');
    96→
    97→    state = const AsyncValue.loading();
    98→    final res = await _profileStorage.setTeamId(teamId);
    99→
   100→    // Refresh user's accessible contents after successful team switch
   101→    if (res && _mounted) {
   102→      await ref
   103→          .read(userAccessibleContentsControllerProvider.notifier)
   104→          .refresh();
   105→    }
   106→
   107→    if (_mounted) {
   108→      state = res
   109→          ? const AsyncValue.data(true)
   110→          : AsyncValue.error('failed to setTeamId', StackTrace.current);
   111→    }
   112→    return res
   113→        ? const Right(true)
   114→        : Left(Failure.undefined(
   115→            code: fc.position('001'),
   116→            description: (l10n) =>
   117→                l10n.login_state_controller__failed_to_switch_team,
   118→          ));
   119→  }
   120→
   121→  Future<Result<Failure, void>> signUp(
   122→    String email,
